import {
  type ButtonHTMLAttributes,
  type CSSProperties,
  forwardRef,
  type ReactNode,
  useContext,
} from 'react';
import { mix } from '@cobos/tokens';
import { cls, useNamespace } from '../../utils';
import { type ComponentSize, useDisabled, useSize } from '../../config-provider';
import { Icon, LoadingIcon } from '../Icon';
import { ButtonGroupContext } from './ButtonGroup';

export type ButtonType =
  | 'default'
  | 'primary'
  | 'success'
  | 'warning'
  | 'info'
  | 'danger';

export type ButtonNativeType = 'button' | 'submit' | 'reset';

export interface ButtonProps extends Omit<ButtonHTMLAttributes<HTMLButtonElement>, 'type'> {
  /** Visual variant. */
  type?: ButtonType;
  /** Size. Falls back to the nearest ButtonGroup / ConfigProvider. */
  size?: ComponentSize;
  /** Native button `type` attribute. */
  nativeType?: ButtonNativeType;
  /** Outlined style. */
  plain?: boolean;
  /** Text-only style (no background or border). */
  text?: boolean;
  /** Keep a background on text buttons. */
  bg?: boolean;
  /** Link style. */
  link?: boolean;
  /** Dashed border. */
  dashed?: boolean;
  /** Rounded corners. */
  round?: boolean;
  /** Circular button (for icon-only). */
  circle?: boolean;
  /** Show a loading spinner and disable interaction. */
  loading?: boolean;
  /** Custom loading icon. */
  loadingIcon?: ReactNode;
  /** Disable the button. */
  disabled?: boolean;
  /** Leading icon. */
  icon?: ReactNode;
  /** Custom base color; hover/active states are derived automatically. */
  color?: string;
  /** Treat `color` as a dark-mode color. */
  dark?: boolean;
  children?: ReactNode;
}

function buildColorStyle(
  color: string,
  plain: boolean,
  dark: boolean,
  text: boolean,
  link: boolean,
): CSSProperties {
  const ns = 'ec-button';
  const blend = dark ? '#141414' : '#ffffff';
  const style: Record<string, string> = {};
  if (text || link) {
    // Text/link buttons keep a transparent background, so only drive the
    // text colors from the custom color and leave bg/border to the
    // is-text / is-link rules.
    style[`--${ns}-text-color`] = color;
    style[`--${ns}-hover-text-color`] = mix(blend, color, 0.3);
    style[`--${ns}-active-text-color`] = mix('#000000', color, 0.1);
  } else if (plain) {
    style[`--${ns}-bg-color`] = mix(blend, color, 0.9);
    style[`--${ns}-text-color`] = color;
    style[`--${ns}-border-color`] = mix(blend, color, 0.5);
    style[`--${ns}-hover-bg-color`] = color;
    style[`--${ns}-hover-text-color`] = blend;
    style[`--${ns}-hover-border-color`] = color;
    style[`--${ns}-active-bg-color`] = mix('#000000', color, 0.1);
    style[`--${ns}-active-text-color`] = blend;
    style[`--${ns}-active-border-color`] = mix('#000000', color, 0.1);
  } else {
    style[`--${ns}-bg-color`] = color;
    style[`--${ns}-text-color`] = '#ffffff';
    style[`--${ns}-border-color`] = color;
    style[`--${ns}-hover-bg-color`] = mix(blend, color, 0.3);
    style[`--${ns}-hover-text-color`] = '#ffffff';
    style[`--${ns}-hover-border-color`] = mix(blend, color, 0.3);
    style[`--${ns}-active-bg-color`] = mix('#000000', color, 0.1);
    style[`--${ns}-active-text-color`] = '#ffffff';
    style[`--${ns}-active-border-color`] = mix('#000000', color, 0.1);
  }
  return style as CSSProperties;
}

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(function Button(props, ref) {
  const group = useContext(ButtonGroupContext);
  const {
    type = group?.type ?? 'default',
    size: sizeProp,
    nativeType = 'button',
    plain = false,
    text = false,
    bg = false,
    link = false,
    dashed = false,
    round = false,
    circle = false,
    loading = false,
    loadingIcon,
    disabled: disabledProp,
    icon,
    color,
    dark = false,
    className,
    style,
    children,
    ...rest
  } = props;

  const ns = useNamespace('button');
  const size = useSize(sizeProp ?? group?.size);
  const disabled = useDisabled(disabledProp) || loading;

  const classes = cls(
    ns.b(),
    type && type !== 'default' && ns.m(type),
    size !== 'default' && ns.m(size),
    ns.is('plain', plain),
    ns.is('round', round),
    ns.is('circle', circle),
    ns.is('text', text),
    ns.is('link', link),
    ns.is('dashed', dashed),
    ns.is('has-bg', bg),
    ns.is('loading', loading),
    ns.is('disabled', disabled),
    className,
  );

  const colorStyle = color ? buildColorStyle(color, plain, dark, text, link) : undefined;

  return (
    <button
      ref={ref}
      type={nativeType}
      className={classes}
      disabled={disabled}
      aria-disabled={disabled || undefined}
      style={{ ...colorStyle, ...style }}
      {...rest}
    >
      {loading ? (
        <Icon className={ns.e('loading')} spin>
          {loadingIcon ?? <LoadingIcon />}
        </Icon>
      ) : (
        icon && <Icon className={ns.e('icon')}>{icon}</Icon>
      )}
      {children !== undefined && children !== null && <span>{children}</span>}
    </button>
  );
});

import { createContext, forwardRef, type HTMLAttributes, useMemo } from 'react';
import { cls, useNamespace } from '../../utils';
import type { ComponentSize } from '../../config-provider';
import type { ButtonType } from './Button';

export interface ButtonGroupContextValue {
  size?: ComponentSize;
  type?: ButtonType;
}

export const ButtonGroupContext = createContext<ButtonGroupContextValue | null>(null);

export interface ButtonGroupProps extends HTMLAttributes<HTMLDivElement> {
  size?: ComponentSize;
  type?: ButtonType;
}

export const ButtonGroup = forwardRef<HTMLDivElement, ButtonGroupProps>(function ButtonGroup(
  { size, type, className, children, ...rest },
  ref,
) {
  const ns = useNamespace('button-group');
  const ctx = useMemo<ButtonGroupContextValue>(() => ({ size, type }), [size, type]);
  return (
    <ButtonGroupContext.Provider value={ctx}>
      <div ref={ref} className={cls(ns.b(), className)} role="group" {...rest}>
        {children}
      </div>
    </ButtonGroupContext.Provider>
  );
});

.ec-button {
  --ec-button-text-color: var(--ec-text-color-regular);
  --ec-button-bg-color: var(--ec-fill-color-blank);
  --ec-button-border-color: var(--ec-border-color);
  --ec-button-hover-text-color: var(--ec-color-primary);
  --ec-button-hover-bg-color: var(--ec-color-primary-light-9);
  --ec-button-hover-border-color: var(--ec-color-primary-light-7);
  --ec-button-active-text-color: var(--ec-color-primary-dark-2);
  --ec-button-active-bg-color: var(--ec-color-primary-light-9);
  --ec-button-active-border-color: var(--ec-color-primary-dark-2);
  --ec-button-disabled-text-color: var(--ec-disabled-text-color);
  --ec-button-disabled-bg-color: var(--ec-fill-color-blank);
  --ec-button-disabled-border-color: var(--ec-border-color-light);
  --ec-button-size: var(--ec-component-size);
  --ec-button-padding-horizontal: 15px;
  --ec-button-font-size: var(--ec-font-size-base);
  --ec-button-border-radius: var(--ec-border-radius-base);

  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  box-sizing: border-box;
  height: var(--ec-button-size);
  padding: 8px var(--ec-button-padding-horizontal);
  margin: 0;
  font-family: inherit;
  font-size: var(--ec-button-font-size);
  font-weight: var(--ec-font-weight-primary);
  line-height: 1;
  white-space: nowrap;
  text-align: center;
  cursor: pointer;
  user-select: none;
  color: var(--ec-button-text-color);
  background-color: var(--ec-button-bg-color);
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-button-border-color);
  border-radius: var(--ec-button-border-radius);
  outline: none;
  appearance: none;
  vertical-align: middle;
  transition: var(--ec-transition-all);
}

.ec-button:hover {
  color: var(--ec-button-hover-text-color);
  background-color: var(--ec-button-hover-bg-color);
  border-color: var(--ec-button-hover-border-color);
}

.ec-button:active {
  color: var(--ec-button-active-text-color);
  background-color: var(--ec-button-active-bg-color);
  border-color: var(--ec-button-active-border-color);
}

.ec-button:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: 1px;
}

.ec-button > span {
  display: inline-flex;
  align-items: center;
}

/* ---- Solid type variants ---- */
.ec-button--primary {
  --ec-button-text-color: var(--ec-color-white);
  --ec-button-bg-color: var(--ec-color-primary);
  --ec-button-border-color: var(--ec-color-primary);
  --ec-button-hover-text-color: var(--ec-color-white);
  --ec-button-hover-bg-color: var(--ec-color-primary-light-3);
  --ec-button-hover-border-color: var(--ec-color-primary-light-3);
  --ec-button-active-text-color: var(--ec-color-white);
  --ec-button-active-bg-color: var(--ec-color-primary-dark-2);
  --ec-button-active-border-color: var(--ec-color-primary-dark-2);
  --ec-button-disabled-text-color: var(--ec-color-white);
  --ec-button-disabled-bg-color: var(--ec-color-primary-light-5);
  --ec-button-disabled-border-color: var(--ec-color-primary-light-5);
}

.ec-button--success {
  --ec-button-text-color: var(--ec-color-white);
  --ec-button-bg-color: var(--ec-color-success);
  --ec-button-border-color: var(--ec-color-success);
  --ec-button-hover-text-color: var(--ec-color-white);
  --ec-button-hover-bg-color: var(--ec-color-success-light-3);
  --ec-button-hover-border-color: var(--ec-color-success-light-3);
  --ec-button-active-text-color: var(--ec-color-white);
  --ec-button-active-bg-color: var(--ec-color-success-dark-2);
  --ec-button-active-border-color: var(--ec-color-success-dark-2);
  --ec-button-disabled-text-color: var(--ec-color-white);
  --ec-button-disabled-bg-color: var(--ec-color-success-light-5);
  --ec-button-disabled-border-color: var(--ec-color-success-light-5);
}

.ec-button--warning {
  --ec-button-text-color: var(--ec-color-white);
  --ec-button-bg-color: var(--ec-color-warning);
  --ec-button-border-color: var(--ec-color-warning);
  --ec-button-hover-text-color: var(--ec-color-white);
  --ec-button-hover-bg-color: var(--ec-color-warning-light-3);
  --ec-button-hover-border-color: var(--ec-color-warning-light-3);
  --ec-button-active-text-color: var(--ec-color-white);
  --ec-button-active-bg-color: var(--ec-color-warning-dark-2);
  --ec-button-active-border-color: var(--ec-color-warning-dark-2);
  --ec-button-disabled-text-color: var(--ec-color-white);
  --ec-button-disabled-bg-color: var(--ec-color-warning-light-5);
  --ec-button-disabled-border-color: var(--ec-color-warning-light-5);
}

.ec-button--danger {
  --ec-button-text-color: var(--ec-color-white);
  --ec-button-bg-color: var(--ec-color-danger);
  --ec-button-border-color: var(--ec-color-danger);
  --ec-button-hover-text-color: var(--ec-color-white);
  --ec-button-hover-bg-color: var(--ec-color-danger-light-3);
  --ec-button-hover-border-color: var(--ec-color-danger-light-3);
  --ec-button-active-text-color: var(--ec-color-white);
  --ec-button-active-bg-color: var(--ec-color-danger-dark-2);
  --ec-button-active-border-color: var(--ec-color-danger-dark-2);
  --ec-button-disabled-text-color: var(--ec-color-white);
  --ec-button-disabled-bg-color: var(--ec-color-danger-light-5);
  --ec-button-disabled-border-color: var(--ec-color-danger-light-5);
}

.ec-button--info {
  --ec-button-text-color: var(--ec-color-white);
  --ec-button-bg-color: var(--ec-color-info);
  --ec-button-border-color: var(--ec-color-info);
  --ec-button-hover-text-color: var(--ec-color-white);
  --ec-button-hover-bg-color: var(--ec-color-info-light-3);
  --ec-button-hover-border-color: var(--ec-color-info-light-3);
  --ec-button-active-text-color: var(--ec-color-white);
  --ec-button-active-bg-color: var(--ec-color-info-dark-2);
  --ec-button-active-border-color: var(--ec-color-info-dark-2);
  --ec-button-disabled-text-color: var(--ec-color-white);
  --ec-button-disabled-bg-color: var(--ec-color-info-light-5);
  --ec-button-disabled-border-color: var(--ec-color-info-light-5);
}

/* ---- Plain ---- */
.ec-button--primary.is-plain {
  --ec-button-text-color: var(--ec-color-primary);
  --ec-button-bg-color: var(--ec-color-primary-light-9);
  --ec-button-border-color: var(--ec-color-primary-light-5);
  --ec-button-hover-text-color: var(--ec-color-white);
  --ec-button-hover-bg-color: var(--ec-color-primary);
  --ec-button-hover-border-color: var(--ec-color-primary);
  --ec-button-active-text-color: var(--ec-color-white);
  --ec-button-active-bg-color: var(--ec-color-primary-dark-2);
  --ec-button-active-border-color: var(--ec-color-primary-dark-2);
}

.ec-button--success.is-plain {
  --ec-button-text-color: var(--ec-color-success);
  --ec-button-bg-color: var(--ec-color-success-light-9);
  --ec-button-border-color: var(--ec-color-success-light-5);
  --ec-button-hover-text-color: var(--ec-color-white);
  --ec-button-hover-bg-color: var(--ec-color-success);
  --ec-button-hover-border-color: var(--ec-color-success);
  --ec-button-active-text-color: var(--ec-color-white);
  --ec-button-active-bg-color: var(--ec-color-success-dark-2);
  --ec-button-active-border-color: var(--ec-color-success-dark-2);
}

.ec-button--warning.is-plain {
  --ec-button-text-color: var(--ec-color-warning);
  --ec-button-bg-color: var(--ec-color-warning-light-9);
  --ec-button-border-color: var(--ec-color-warning-light-5);
  --ec-button-hover-text-color: var(--ec-color-white);
  --ec-button-hover-bg-color: var(--ec-color-warning);
  --ec-button-hover-border-color: var(--ec-color-warning);
  --ec-button-active-text-color: var(--ec-color-white);
  --ec-button-active-bg-color: var(--ec-color-warning-dark-2);
  --ec-button-active-border-color: var(--ec-color-warning-dark-2);
}

.ec-button--danger.is-plain {
  --ec-button-text-color: var(--ec-color-danger);
  --ec-button-bg-color: var(--ec-color-danger-light-9);
  --ec-button-border-color: var(--ec-color-danger-light-5);
  --ec-button-hover-text-color: var(--ec-color-white);
  --ec-button-hover-bg-color: var(--ec-color-danger);
  --ec-button-hover-border-color: var(--ec-color-danger);
  --ec-button-active-text-color: var(--ec-color-white);
  --ec-button-active-bg-color: var(--ec-color-danger-dark-2);
  --ec-button-active-border-color: var(--ec-color-danger-dark-2);
}

.ec-button--info.is-plain {
  --ec-button-text-color: var(--ec-color-info);
  --ec-button-bg-color: var(--ec-color-info-light-9);
  --ec-button-border-color: var(--ec-color-info-light-5);
  --ec-button-hover-text-color: var(--ec-color-white);
  --ec-button-hover-bg-color: var(--ec-color-info);
  --ec-button-hover-border-color: var(--ec-color-info);
  --ec-button-active-text-color: var(--ec-color-white);
  --ec-button-active-bg-color: var(--ec-color-info-dark-2);
  --ec-button-active-border-color: var(--ec-color-info-dark-2);
}

/* ---- Text & link ---- */
.ec-button.is-text {
  --ec-button-bg-color: transparent;
  --ec-button-border-color: transparent;
  --ec-button-hover-bg-color: var(--ec-fill-color-light);
  --ec-button-hover-border-color: transparent;
  --ec-button-active-bg-color: var(--ec-fill-color);
  --ec-button-active-border-color: transparent;
}

.ec-button.is-text.is-has-bg {
  --ec-button-bg-color: var(--ec-fill-color-light);
}

.ec-button--primary.is-text {
  --ec-button-text-color: var(--ec-color-primary);
  --ec-button-hover-text-color: var(--ec-color-primary);
  --ec-button-active-text-color: var(--ec-color-primary-dark-2);
}
.ec-button--success.is-text {
  --ec-button-text-color: var(--ec-color-success);
  --ec-button-hover-text-color: var(--ec-color-success);
  --ec-button-active-text-color: var(--ec-color-success-dark-2);
}
.ec-button--warning.is-text {
  --ec-button-text-color: var(--ec-color-warning);
  --ec-button-hover-text-color: var(--ec-color-warning);
  --ec-button-active-text-color: var(--ec-color-warning-dark-2);
}
.ec-button--danger.is-text {
  --ec-button-text-color: var(--ec-color-danger);
  --ec-button-hover-text-color: var(--ec-color-danger);
  --ec-button-active-text-color: var(--ec-color-danger-dark-2);
}
.ec-button--info.is-text {
  --ec-button-text-color: var(--ec-color-info);
  --ec-button-hover-text-color: var(--ec-color-info);
  --ec-button-active-text-color: var(--ec-color-info-dark-2);
}

.ec-button.is-link {
  --ec-button-bg-color: transparent;
  --ec-button-border-color: transparent;
  --ec-button-hover-bg-color: transparent;
  --ec-button-hover-border-color: transparent;
  --ec-button-active-bg-color: transparent;
  --ec-button-active-border-color: transparent;
  height: auto;
  padding: 2px 0;
}
.ec-button--primary.is-link {
  --ec-button-text-color: var(--ec-color-primary);
  --ec-button-hover-text-color: var(--ec-color-primary-light-3);
  --ec-button-active-text-color: var(--ec-color-primary-dark-2);
}
.ec-button--success.is-link {
  --ec-button-text-color: var(--ec-color-success);
  --ec-button-hover-text-color: var(--ec-color-success-light-3);
  --ec-button-active-text-color: var(--ec-color-success-dark-2);
}
.ec-button--warning.is-link {
  --ec-button-text-color: var(--ec-color-warning);
  --ec-button-hover-text-color: var(--ec-color-warning-light-3);
  --ec-button-active-text-color: var(--ec-color-warning-dark-2);
}
.ec-button--danger.is-link {
  --ec-button-text-color: var(--ec-color-danger);
  --ec-button-hover-text-color: var(--ec-color-danger-light-3);
  --ec-button-active-text-color: var(--ec-color-danger-dark-2);
}
.ec-button--info.is-link {
  --ec-button-text-color: var(--ec-color-info);
  --ec-button-hover-text-color: var(--ec-color-info-light-3);
  --ec-button-active-text-color: var(--ec-color-info-dark-2);
}

/* ---- Shapes & modifiers ---- */
.ec-button.is-dashed {
  border-style: dashed;
}

.ec-button.is-round {
  --ec-button-border-radius: var(--ec-border-radius-round);
}

.ec-button.is-circle {
  width: var(--ec-button-size);
  padding: 8px;
  border-radius: 50%;
}

.ec-button.is-disabled,
.ec-button.is-disabled:hover,
.ec-button.is-disabled:active,
.ec-button:disabled {
  color: var(--ec-button-disabled-text-color);
  background-color: var(--ec-button-disabled-bg-color);
  border-color: var(--ec-button-disabled-border-color);
  cursor: not-allowed;
}

.ec-button.is-loading {
  position: relative;
  cursor: default;
  pointer-events: none;
}

/* ---- Sizes ---- */
.ec-button--large {
  --ec-button-size: var(--ec-component-size-large);
  --ec-button-padding-horizontal: 19px;
}
.ec-button--small {
  --ec-button-size: var(--ec-component-size-small);
  --ec-button-padding-horizontal: 11px;
  --ec-button-font-size: var(--ec-font-size-extra-small);
}

/* ---- Button group ---- */
.ec-button-group {
  display: inline-flex;
  vertical-align: middle;
}
.ec-button-group > .ec-button:not(:last-child) {
  margin-right: -1px;
}
.ec-button-group > .ec-button:not(:first-child):not(:last-child) {
  border-radius: 0;
}
.ec-button-group > .ec-button:first-child {
  border-top-right-radius: 0;
  border-bottom-right-radius: 0;
}
.ec-button-group > .ec-button:last-child {
  border-top-left-radius: 0;
  border-bottom-left-radius: 0;
}
.ec-button-group > .ec-button:hover,
.ec-button-group > .ec-button:focus-visible {
  position: relative;
  z-index: 1;
}
